const GLOBAL_VIDEO_URL = "https://www.youtube.com/embed/Sq7a991gC2c?si=dsMpKEvxEvreKRnw";

const App: React.FC = () => {
  const [currentScreen, setCurrentScreen] = useState<AppScreen>(AppScreen.WELCOME);
  const [selectedPlatform, setSelectedPlatform] = useState<Platform | null>(null);
  const [activeProduct, setActiveProduct] = useState<ProductData | null>(null);
  const [paymentId, setPaymentId] = useState<string | null>(null);

  const isLocked = () => {
    const unlockDate = new Date('2026-01-20T00:00:00');
    return new Date() < unlockDate;
  };

  const getThemeColor = (platform: Platform | null) => {
    switch(platform) {
      case Platform.NOVA: return '#00f2ff';
      case Platform.MJ: return '#7000ff';
      case Platform.SPECIAL_OFFER: return '#ff00d4';
      case Platform.ANDROID: return '#22c55e';
      default: return '#00f2ff';
    }
  };

  const themeColor = getThemeColor(selectedPlatform);

  useEffect(() => {
    document.documentElement.style.setProperty('--primary-theme', themeColor);
  }, [themeColor]);

  const navigateTo = (screen: AppScreen) => {
    setCurrentScreen(screen);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handlePlatformSelect = (platform: Platform) => {
    if (platform === Platform.SPECIAL_OFFER && isLocked()) return;

    setSelectedPlatform(platform);
    if (platform === Platform.SPECIAL_OFFER) {
      navigateTo(AppScreen.VARIANTS);
    } else if (platform === Platform.ANDROID) {
      setActiveProduct({
        id: 'android-source',
        title: 'NOVA AI ANDROID SOURCE',
        subtitle: 'Professional Mobile Intelligence Infrastructure',
        price: 1499,
        platform: Platform.ANDROID,
        videoUrl: GLOBAL_VIDEO_URL,
        features: ANDROID_FEATURES,
        variantName: 'FULL ZIP'
      });
      navigateTo(AppScreen.PRODUCT_DETAILS);
    } else {
      navigateTo(AppScreen.PRODUCT_OPTIONS);
    }
  };

  const handleNovaVariant = (variantId: string) => {
    setActiveProduct({
      id: 'nova-vadryk',
      title: 'NOVA 4.0 VADRYK ELITE',
      subtitle: 'The Ultimate Autonomous Engine',
      price: 899,
      originalPrice: 1199,
      platform: Platform.NOVA,
      variantName: 'ELITE',
      videoUrl: GLOBAL_VIDEO_URL,
      features: ELITE_FEATURES
    });
    navigateTo(AppScreen.PRODUCT_DETAILS);
  };

  const handleMJVariant = (variantId: string, price: number) => {
    setActiveProduct({
      id: 'mj-v1',
      title: 'MJ v1 Emotionally Human AI',
      subtitle: 'Cognitive Empathy & Neural Connection',
      price: price,
      platform: Platform.MJ,
      variantName: 'EMPATHY',
      videoUrl: GLOBAL_VIDEO_URL,
      features: ELITE_FEATURES
    });
    navigateTo(AppScreen.PRODUCT_DETAILS);
  };

  const handleComboSelect = (price: number) => {
    setActiveProduct({
      id: 'combo',
      title: 'UNIFIED NOVA & MJ COMBO',
      subtitle: 'Elite Performance & Human Empathy Combined',
      price: price,
      originalPrice: 1999,
      platform: Platform.SPECIAL_OFFER,
      videoUrl: GLOBAL_VIDEO_URL,
      features: ELITE_FEATURES,
      variantName: 'UNIFIED'
    });
    navigateTo(AppScreen.PRODUCT_DETAILS);
  };

  const handleOptionSelect = (option: string) => {
    const platformTag = selectedPlatform?.toUpperCase() || 'NOVA';

    if (option === 'windows-app') {
       navigateTo(AppScreen.VARIANTS);
    } else if (option === 'source-code') {
       if (isLocked()) return;
       setActiveProduct({
        id: 'full-source',
        title: `${platformTag} FULL SOURCE CODE`,
        subtitle: 'Enterprise AI Development Assets',
        price: 5999,
        originalPrice: 13999,
        platform: selectedPlatform || Platform.NOVA,
        variantName: 'STUDENT SOURCE',
        videoUrl: GLOBAL_VIDEO_URL,
        features: ELITE_FEATURES
      });
      navigateTo(AppScreen.PRODUCT_DETAILS);
    } else if (option === 'custom-name') {
      setActiveProduct({
        id: 'custom-ai',
        title: `CUSTOM BRANDED ${platformTag} AI`,
        subtitle: 'Your Name. Your Voice. Your Brand.',
        price: 1999,
        originalPrice: 3500,
        platform: selectedPlatform || Platform.NOVA,
        variantName: 'CUSTOM',
        videoUrl: GLOBAL_VIDEO_URL,
        features: ELITE_FEATURES,
        isCustom: true
      });
      navigateTo(AppScreen.PRODUCT_DETAILS);
    }
  };

  const startPayment = () => {
    if (!activeProduct) return;
    const script = document.createElement('script');
    script.src = 'https://checkout.razorpay.com/v1/checkout.js';
    script.onload = () => {
      const options = {
        key: 'rzp_test_RJ7MCxKglW6ylV',
        amount: activeProduct.price * 100,
        currency: 'INR',
        name: `${selectedPlatform?.toUpperCase()} AI PLATFORM`,
        description: `Activation for ${activeProduct.title}`,
        handler: function(response: any) {
          setPaymentId(response.razorpay_payment_id);
          navigateTo(AppScreen.PAYMENT_FORM);
        },
        theme: { color: themeColor }
      };
      const rzp = new (window as any).Razorpay(options);
      rzp.open();
    };
    document.body.appendChild(script);
  };

  const handleFinalSubmit = (details: UserDetails) => {
    if (!activeProduct || !paymentId) return;
    const invoiceNo = `${selectedPlatform?.toUpperCase()}-ELITE-${Date.now()}`;

    let targetPhone = "919512194144";
    const isSpecialOrder = activeProduct.id === 'combo' || 
                             activeProduct.variantName === 'ELITE' || 
                             activeProduct.variantName === 'EMPATHY' ||
                             activeProduct.variantName === 'UNIFIED';

    if (isSpecialOrder) {
      const phones = ["919512194144", "917574821527"];
      targetPhone = phones[Math.floor(Math.random() * phones.length)];
    }

    let message = `Hello! I just purchased ${activeProduct.title}.

📋 *OFFICIAL INVOICE:*
─────────────────
🆔 *Invoice:* ${invoiceNo}
💳 *Payment ID:* ${paymentId}
📦 *Product:* ${activeProduct.title}
💰 *Amount:* ₹${activeProduct.price}

👤 *CUSTOMER:*
─────────────────
📛 *Name:* ${details.name}
📧 *Email:* ${details.email}`;

    if (details.desiredAiName) {
      message += `\n🤖 *Desired AI Name:* ${details.desiredAiName.toUpperCase()}`;
    }

    message += `\n\nPlease provide my ELITE access credentials for ${selectedPlatform?.toUpperCase()} AI. Thank you! 🚀`;

    window.open(`https://wa.me/${targetPhone}?text=${encodeURIComponent(message)}`, '_blank');
  };

  return (
    <div className="min-h-screen font-exo text-text-primary selection:bg-primary selection:text-surface" style={{ '--theme-color': themeColor } as any}>
      <Header currentScreen={currentScreen} onNavigate={navigateTo} themeColor={themeColor} platformName={selectedPlatform?.toUpperCase() || 'NOVA'} />

      <main className="container mx-auto px-4 py-24 relative z-10">
        {currentScreen === AppScreen.WELCOME && <WelcomeScreen onContinue={() => navigateTo(AppScreen.MAIN_SELECTION)} />}
        {currentScreen === AppScreen.MAIN_SELECTION && <MainSelectionScreen onPlatformSelect={handlePlatformSelect} />}
        {currentScreen === AppScreen.PRODUCT_OPTIONS && <ProductOptionsScreen platform={selectedPlatform} onBack={() => navigateTo(AppScreen.MAIN_SELECTION)} onSelectOption={handleOptionSelect} themeColor={themeColor} />}

        {currentScreen === AppScreen.VARIANTS && selectedPlatform === Platform.NOVA && <NovaVariantSelector onBack={() => navigateTo(AppScreen.PRODUCT_OPTIONS)} onSelect={handleNovaVariant} />}
        {currentScreen === AppScreen.VARIANTS && selectedPlatform === Platform.MJ && <MJVariantSelector onBack={() => navigateTo(AppScreen.PRODUCT_OPTIONS)} onSelect={handleMJVariant} />}
        {currentScreen === AppScreen.VARIANTS && selectedPlatform === Platform.SPECIAL_OFFER && <ComboVariantSelector onBack={() => navigateTo(AppScreen.MAIN_SELECTION)} onSelect={handleComboSelect} />}

        {currentScreen === AppScreen.PRODUCT_DETAILS && activeProduct && <ProductDetailsPage product={activeProduct} onBack={() => navigateTo(AppScreen.MAIN_SELECTION)} onPurchase={startPayment} themeColor={themeColor} />}
        {currentScreen === AppScreen.PAYMENT_FORM && activeProduct && paymentId && (
          <PaymentForm 
            productTitle={activeProduct.title} 
            price={activeProduct.price} 
            paymentId={paymentId} 
            isCustomProduct={!!activeProduct.isCustom}
            onSubmit={handleFinalSubmit} 
            themeColor={themeColor}
          />
        )}

        {currentScreen === AppScreen.CONTACT && <GenericPage title="Contact Us" onBack={() => navigateTo(AppScreen.MAIN_SELECTION)} content={<div>Contact logic...</div>} />}
        {currentScreen === AppScreen.ABOUT && <GenericPage title="About Us" onBack={() => navigateTo(AppScreen.MAIN_SELECTION)} content={<div>About logic...</div>} />}
        {currentScreen === AppScreen.REFUND && <GenericPage title="Refund Policy" onBack={() => navigateTo(AppScreen.MAIN_SELECTION)} content={<div>Refund logic...</div>} />}
        {currentScreen === AppScreen.DISTRIBUTION && <GenericPage title="Distribution Policy" onBack={() => navigateTo(AppScreen.MAIN_SELECTION)} content={<div>Delivery logic...</div>} />}
        {currentScreen === AppScreen.PRIVACY && <GenericPage title="Privacy Policy" onBack={() => navigateTo(AppScreen.MAIN_SELECTION)} content={<div>Privacy logic...</div>} />}
        {currentScreen === AppScreen.TERMS && <GenericPage title="Terms & Conditions" onBack={() => navigateTo(AppScreen.MAIN_SELECTION)} content={<div>Terms logic...</div>} />}
      </main>
    </div>
  );
};

