        {currentScreen === AppScreen.PAYMENT_FORM && activeProduct && paymentId && (
          <PaymentForm 
            productTitle={activeProduct.title} 
            price={activeProduct.price} 
            paymentId={paymentId} 
            isCustomProduct={!!activeProduct.isCustom}
            onSubmit={handleFinalSubmit} 
            themeColor={themeColor}
          />
        )}

        {currentScreen === AppScreen.CONTACT && <GenericPage title="Contact Us" onBack={() => navigateTo(AppScreen.MAIN_SELECTION)} content={contactContent} />}
        {currentScreen === AppScreen.ABOUT && <GenericPage title="About Us" onBack={() => navigateTo(AppScreen.MAIN_SELECTION)} content={aboutContent} />}
        {currentScreen === AppScreen.REFUND && <GenericPage title="Refund Policy" onBack={() => navigateTo(AppScreen.MAIN_SELECTION)} content={refundContent} />}
        {currentScreen === AppScreen.DISTRIBUTION && <GenericPage title="Distribution Policy" onBack={() => navigateTo(AppScreen.MAIN_SELECTION)} content={distributionContent} />}
        {currentScreen === AppScreen.PRIVACY && <GenericPage title="Privacy Policy" onBack={() => navigateTo(AppScreen.MAIN_SELECTION)} content={privacyContent} />}
        {currentScreen === AppScreen.TERMS && <GenericPage title="Terms & Conditions" onBack={() => navigateTo(AppScreen.MAIN_SELECTION)} content={termsContent} />}
      </main>
    </div>
  );
};

export default App;

