import React, { useState, useRef, useEffect } from 'react';

interface Message {
  id: number;
  text: React.ReactNode;
  sender: 'user' | 'bot';
  timestamp: Date;
}

const SupportChatBot: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isTyping, setIsTyping] = useState(false);
  const [inputText, setInputText] = useState('');
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 1,
      text: "Hello! I am NOVA Support AI. 🤖\n\nI can help you with:\n1. Product Details (Nova/MJ)\n2. Payment & Delivery\n3. Technical Issues\n\nHow can I assist you today?",
      sender: 'bot',
      timestamp: new Date()
    }
  ]);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isOpen, isTyping]);

  const generateResponse = (input: string): React.ReactNode => {
    const lowerInput = input.toLowerCase();

    // 1. Payment / WhatsApp / Delivery Failure Logic (CRITICAL)
    if (
      lowerInput.includes('payment') || 
      lowerInput.includes('paise') || 
      lowerInput.includes('kat gaye') || 
      lowerInput.includes('whatsapp') || 
      lowerInput.includes('key') || 
      lowerInput.includes('code') ||
      lowerInput.includes('refund') ||
      lowerInput.includes('scam') ||
      lowerInput.includes('mila nahi') ||
      lowerInput.includes('not received')
    ) {
      return (
        <span>
          <strong className="text-red-400">⚠️ IMPORTANT UPDATE:</strong><br/><br/>
          If your payment was successful but you didn't get the key on WhatsApp, <strong>don't worry! Your money is safe.</strong><br/><br/>
          Sometimes tech glitches happen. Please follow these steps:<br/>
          1. Take a screenshot of your payment.<br/>
          2. Send it manually to the Owner: <strong>+91 95121 94144</strong><br/>
          3. Mention "Payment Done, Key Pending".<br/><br/>
          <strong className="text-primary">Ankit Singh</strong> will verify and generate your key manually within 30 minutes.
        </span>
      );
    }

    // 2. NOVA AI Queries
    if (lowerInput.includes('nova') || lowerInput.includes('vadryk')) {
      return (
        <span>
          <strong>NOVA 4.0 VADRYK</strong> is our flagship Windows Automation Engine.<br/><br/>
          <strong>Key Features:</strong><br/>
          • Opens files/apps instantly.<br/>
          • Controls mouse & keyboard.<br/>
          • Deep system telemetry.<br/>
          • Works fully offline for privacy.
        </span>
      );
    }

    // 3. MJ AI Queries
    if (lowerInput.includes('mj') || lowerInput.includes('emotion') || lowerInput.includes('girl')) {
      return (
        <span>
          <strong>MJ v1</strong> is the Empathy Engine.<br/><br/>
          Unlike Nova (which is logical), MJ is designed to be a <strong>companion</strong>. It understands emotions, remembers conversations, and provides a human-like connection on your PC.
        </span>
      );
    }

    // 4. Android Queries
    if (lowerInput.includes('android') || lowerInput.includes('mobile') || lowerInput.includes('phone')) {
      return "The Android Source code package allows you to build your own mobile assistant. You get the full Android Studio project file (Java/Kotlin) to modify and deploy as your own app.";
    }

    // 5. Price / Cost
    if (lowerInput.includes('price') || lowerInput.includes('cost') || lowerInput.includes('kitne') || lowerInput.includes('rate')) {
      return (
        <span>
          <strong>Current Pricing:</strong><br/>
          • NOVA Elite: ₹899<br/>
          • MJ Empathy: ₹899<br/>
          • Combo (Best Value): ₹1499<br/>
          • Android Source: ₹1499<br/>
          • Full Source Code: ₹8,999
        </span>
      );
    }

    // 6. Greetings / General
    if (lowerInput.includes('hello') || lowerInput.includes('hi') || lowerInput.includes('namaste') || lowerInput.includes('hey')) {
      return "Hello there! 👋 I am ready to assist. Ask me anything about Nova, MJ, or payment support.";
    }

    // Default Fallback
    return "I am not sure I understand. If you have a specific issue with payment or activation, please type 'Payment issue'. Otherwise, ask about Nova or MJ!";
  };

  const handleSend = (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim()) return;

    const userMsg: Message = {
      id: Date.now(),
      text: inputText,
      sender: 'user',
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setIsTyping(true);

    // Simulate thinking delay
    setTimeout(() => {
      const botResponse: Message = {
        id: Date.now() + 1,
        text: generateResponse(userMsg.text as string),
        sender: 'bot',
        timestamp: new Date()
      };
      setMessages(prev => [...prev, botResponse]);
      setIsTyping(false);
    }, 1500);
  };

  return (
    <>
      {/* Trigger Button */}
      <button
        onClick={() => setIsOpen(!isOpen)}
        className={`fixed bottom-6 right-6 z-50 w-14 h-14 md:w-16 md:h-16 rounded-full bg-primary text-surface shadow-[0_0_30px_rgba(0,242,255,0.4)] flex items-center justify-center transition-all duration-300 hover:scale-110 active:scale-95 ${isOpen ? 'rotate-90' : 'animate-bounce'}`}
      >
        <i className={`fas ${isOpen ? 'fa-times' : 'fa-robot'} text-2xl`}></i>
      </button>

      {/* Chat Window */}
      <div 
        className={`fixed z-50 bg-surface-lighter/95 backdrop-blur-xl border border-primary/30 shadow-2xl transition-all duration-500 overflow-hidden flex flex-col
          ${isOpen 
            ? 'bottom-24 right-4 w-[90vw] md:w-[380px] h-[60vh] md:h-[600px] opacity-100 scale-100 rounded-[2rem]' 
            : 'bottom-6 right-6 w-0 h-0 opacity-0 scale-0 rounded-full'
          }
        `}
      >
        {/* Header */}
        <div className="p-4 bg-gradient-to-r from-primary/20 to-secondary/20 border-b border-white/5 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="relative">
              <div className="w-10 h-10 rounded-full bg-primary/20 flex items-center justify-center border border-primary/50">
                <i className="fas fa-robot text-primary"></i>
              </div>
              <div className="absolute bottom-0 right-0 w-3 h-3 bg-green-500 rounded-full border-2 border-surface"></div>
            </div>
            <div>
              <h3 className="font-orbitron font-bold text-white text-sm">NOVA SUPPORT</h3>
              <p className="text-[10px] text-primary animate-pulse">Online & Ready</p>
            </div>
          </div>
          <button onClick={() => setIsOpen(false)} className="text-text-secondary hover:text-white transition-colors">
            <i className="fas fa-chevron-down"></i>
          </button>
        </div>

        {/* Messages Area */}
        <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar">
          {messages.map((msg) => (
            <div 
              key={msg.id} 
              className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}
            >
              <div 
                className={`max-w-[85%] p-3 md:p-4 rounded-2xl text-xs md:text-sm leading-relaxed ${
                  msg.sender === 'user' 
                    ? 'bg-primary text-surface font-bold rounded-tr-none' 
                    : 'bg-white/10 text-white border border-white/5 rounded-tl-none'
                }`}
              >
                {msg.text}
                <div className={`text-[9px] mt-2 opacity-60 ${msg.sender === 'user' ? 'text-surface' : 'text-text-secondary'}`}>
                  {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </div>
              </div>
            </div>
          ))}

          {isTyping && (
            <div className="flex justify-start animate-pulse">
              <div className="bg-white/5 px-4 py-3 rounded-2xl rounded-tl-none border border-white/5 flex space-x-1">
                <div className="w-1.5 h-1.5 bg-primary rounded-full animate-bounce"></div>
                <div className="w-1.5 h-1.5 bg-primary rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
                <div className="w-1.5 h-1.5 bg-primary rounded-full animate-bounce" style={{ animationDelay: '0.4s' }}></div>
              </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>

        {/* Input Area */}
        <form onSubmit={handleSend} className="p-4 bg-white/5 border-t border-white/5 flex space-x-2">
          <input 
            type="text" 
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            placeholder="Type your question..."
            className="flex-grow bg-black/20 border border-white/10 rounded-xl px-4 py-3 text-sm text-white focus:border-primary outline-none transition-colors placeholder:text-text-secondary/50"
          />
          <button 
            type="submit"
            disabled={!inputText.trim()}
            className="w-12 h-12 bg-primary text-surface rounded-xl flex items-center justify-center shadow-lg hover:scale-105 active:scale-95 transition-all disabled:opacity-50 disabled:scale-100"
          >
            <i className="fas fa-paper-plane"></i>
          </button>
        </form>
      </div>
    </>
  );
};

export default SupportChatBot;

