            productTitle={activeProduct.title}
            price={activeProduct.price}
            paymentId={paymentId || 'PENDING'}
            isCustomProduct={activeProduct.isCustom || false}
            onSubmit={handlePaymentSubmit}
            themeColor={themeColor}
          />
        ) : null;
      case AppScreen.CONTACT:
        return <GenericPage title="Contact Support" onBack={() => navigateTo(AppScreen.MAIN_SELECTION)} content={<p>WhatsApp: +91 95121 94144<br/>Email: support@novaai.com</p>} />;
      case AppScreen.ABOUT:
        return <GenericPage title="About Nova" onBack={() => navigateTo(AppScreen.MAIN_SELECTION)} content={<p>Nova AI is a next-generation automation platform.</p>} />;
      case AppScreen.DISTRIBUTION:
        return <GenericPage title="Delivery Policy" onBack={() => navigateTo(AppScreen.MAIN_SELECTION)} content={<p>Instant delivery via WhatsApp after payment verification.</p>} />;
      case AppScreen.SHIPPING:
        return <GenericPage title="Shipping" onBack={() => navigateTo(AppScreen.MAIN_SELECTION)} content={<p>Digital products are shipped electronically instantly.</p>} />;
      case AppScreen.REFUND:
        return <GenericPage title="Refund Policy" onBack={() => navigateTo(AppScreen.MAIN_SELECTION)} content={<p>No refunds on digital keys once delivered.</p>} />;
      case AppScreen.PRIVACY:
        return <GenericPage title="Privacy Policy" onBack={() => navigateTo(AppScreen.MAIN_SELECTION)} content={<p>We do not store your personal chat data.</p>} />;
      case AppScreen.TERMS:
        return <GenericPage title="Terms of Service" onBack={() => navigateTo(AppScreen.MAIN_SELECTION)} content={<p>By purchasing you agree to the single-user license.</p>} />;
      default:
        return <WelcomeScreen onContinue={() => navigateTo(AppScreen.MAIN_SELECTION)} />;
    }
  };

  return (
    <div className="min-h-screen font-exo text-text-primary selection:bg-primary selection:text-black">
      {currentScreen !== AppScreen.WELCOME && (
        <Header 
          currentScreen={currentScreen} 
          onNavigate={navigateTo} 
          themeColor={themeColor}
          platformName={selectedPlatform?.toUpperCase() || 'NOVA'}
        />
      )}

      <main className={`container mx-auto px-4 md:px-6 ${currentScreen !== AppScreen.WELCOME ? 'pt-24 md:pt-32 pb-20' : ''}`}>
        {renderScreen()}
      </main>

      <SupportChatBot />
    </div>
  );
};

