import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";

interface Message {
  id: number;
  text: React.ReactNode;
  sender: 'user' | 'bot';
  timestamp: Date;
  isError?: boolean;
}

const SYSTEM_INSTRUCTION = `You are NOVA NEXUS, the official AI assistant for the NOVA AI Website (created by Ankit Singh).
Your role is to help users with Products, Payments, Installation, and Website Policies.

CORE KNOWLEDGE BASE:

1. PRODUCT CATALOG:
- **NOVA 4.0 (Vadryk Engine)**: ₹899. Windows Automation. Features: Mouse/Keyboard control, Open Apps, System Telemetry.
- **MJ v1 (Empathy Engine)**: ₹899. Windows Companion. Features: Emotional Memory, Deep Conversation.
- **ANDROID SOURCE CODE**: ₹1499. Full Java/Kotlin project for Android Studio.

2. WEBSITE POLICIES (Strict & Professional):
- **SHIPPING/DELIVERY**: 
  - Instant Digital Delivery via WhatsApp Automated Bot.
  - Time: 0-30 Minutes after payment.
  - Process: User pays -> Fills Google Form -> System sends Key & Link to WhatsApp.
- **REFUND POLICY**: 
  - "Since this is a digital product (Source Code & License Keys), NO REFUNDS are possible once the key is delivered."
  - Exception: If the key is invalid (verified by support).
- **PRIVACY POLICY**: 
  - We do not store personal chat logs. Nova runs locally on your machine.
  - Payment details are processed via secure gateway, we only receive Transaction ID.
- **TERMS**: 
  - Single User License.
  - Reselling the source code without "Enterprise" license is prohibited.

3. SUPPORT & CONTACT:
- **WhatsApp Support**: +91 95121 94144
- **Email**: support@novaai.com (Hypothetical, prefer WhatsApp)
- **Payment Issues**: "If money is deducted but key not received, WhatsApp the screenshot to +91 95121 94144 immediately."

4. BEHAVIOR:
- Answer ANY question about the website, policies, or products.
- Use Hinglish if the user does. (e.g., "Han, payment secure hai.")
- Be concise, futuristic, and polite.
- Format with **Bold** and lists.
`;

const SupportChatBot: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isTyping, setIsTyping] = useState(false);
  const [inputText, setInputText] = useState('');

  const [messages, setMessages] = useState<Message[]>([
    {
      id: 1,
      text: (
        <span>
          Hello! I am <strong>NOVA NEXUS</strong>. 🤖<br/><br/>
          I can help you with:<br/>
          📦 <strong>Products & Features</strong><br/>
          🚚 <strong>Shipping & Delivery</strong><br/>
          💸 <strong>Refunds & Payments</strong><br/>
          🔒 <strong>Privacy & Terms</strong><br/><br/>
          Ask me anything about the website!
        </span>
      ),
      sender: 'bot',
      timestamp: new Date()
    }
  ]);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isOpen, isTyping]);

  // Basic Markdown Formatter for AI Responses
  const formatResponse = (text: string): React.ReactNode => {
    if (!text) return null;
    const lines = text.split('\n');
    return (
      <span className="block space-y-1">
        {lines.map((line, i) => {
          if (line.trim().startsWith('* ') || line.trim().startsWith('- ')) {
            return <span key={i} className="block pl-4">• {formatBold(line.substring(2))}</span>;
          }
          if (/^\d+\./.test(line.trim())) {
             return <span key={i} className="block pl-4">{formatBold(line)}</span>;
          }
          if (line.trim() === '') return <br key={i}/>;
          return <span key={i} className="block">{formatBold(line)}</span>;
        })}
      </span>
    );
  };

  const formatBold = (text: string) => {
    const parts = text.split(/(\*\*.*?\*\*)/g);
    return parts.map((part, index) => {
      if (part.startsWith('**') && part.endsWith('**')) {
        return <strong key={index} className="text-white font-bold">{part.slice(2, -2)}</strong>;
      }
      return part;
    });
  };

  const generateFallbackResponse = (input: string): string => {
    const lower = input.toLowerCase();
    if (lower.includes('payment') || lower.includes('fail') || lower.includes('money')) {
      return "**Payment Issue?**\nDon't worry, your money is safe.\n1. Take a screenshot.\n2. WhatsApp **+91 95121 94144**.\n3. Message: 'Payment Done, Key Pending'.";
    }
    if (lower.includes('refund')) {
      return "**Refund Policy**:\nSince these are digital products (Source Code/Keys), requests are generally **non-refundable** once delivered. Please contact WhatsApp support if the key is not working.";
    }
    return "I am currently offline, but you can contact support at **+91 95121 94144** for immediate help.";
  };

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim()) return;

    const userText = inputText;
    const userMsg: Message = {
      id: Date.now(),
      text: userText,
      sender: 'user',
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const response = await ai.models.generateContent({
        model: 'gemini-2.0-flash-exp',
        contents: `${SYSTEM_INSTRUCTION}\n\nUser Query: ${userText}`,
      });

      const aiText = response.text;

      if (!aiText) {
        throw new Error("No response from AI");
      }

      const botResponse: Message = {
        id: Date.now() + 1,
        text: formatResponse(aiText),
        sender: 'bot',
        timestamp: new Date()
      };
      setMessages(prev => [...prev, botResponse]);

    } catch (error: any) {
      console.error("Chat Error:", error);

      // Use fallback logic if API fails due to quota or network
      const fallbackResponse = generateFallbackResponse(userText);
      const errorMsg: Message = {
        id: Date.now() + 1,
        text: formatResponse("⚠️ **Connection/Quota Error**: Switching to offline mode.\n\n" + fallbackResponse),
        sender: 'bot',
        timestamp: new Date(),
        isError: true
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <>
      {/* Trigger Button */}
      <button
        onClick={() => setIsOpen(!isOpen)}
        className={`fixed bottom-6 right-6 z-50 w-14 h-14 md:w-16 md:h-16 rounded-full bg-primary text-black shadow-[0_0_40px_rgba(0,242,255,0.6)] flex items-center justify-center transition-all duration-300 hover:scale-110 active:scale-95 border-2 border-white/20 ${isOpen ? 'rotate-90' : 'animate-bounce-slow'}`}
        aria-label="Open Support Chat"
      >
        {isOpen ? (
          <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-8 h-8">
            <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
          </svg>
        ) : (
          <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-8 h-8">
             <path strokeLinecap="round" strokeLinejoin="round" d="M8.25 3v1.5M4.5 8.25H3m18 0h-1.5M4.5 12h1.5m12 0h1.5m-1.5 3.75h1.5m-16.5 0h1.5M12 3v2.25m0 12.75V12m0 12.75v-1.5M12 21.75c-1.371 0-2.628-.276-3.75-.783-1.636-.74-2.92-1.956-3.763-3.468C4.09 16.666 4.29 15.698 4.5 14.815c.196-.827.818-1.5 1.636-1.77.72-.239 1.488-.367 2.276-.376a6.006 6.006 0 015.176 0c.788.009 1.556.137 2.276.376.818.27 1.44.943 1.636 1.77.21.883.41 1.851.013 2.689-.843 1.512-2.127 2.728-3.763 3.469-1.122.507-2.379.783-3.75.783z" />
          </svg>
        )}
        {!isOpen && (
          <span className="absolute -top-1 -right-1 w-4 h-4 bg-green-500 rounded-full animate-ping"></span>
        )}
      </button>

      {/* Chat Window */}
      <div 
        className={`fixed z-50 bg-[#0a0a12]/95 backdrop-blur-xl border border-primary/40 shadow-2xl transition-all duration-500 overflow-hidden flex flex-col origin-bottom-right
          ${isOpen 
            ? 'bottom-24 right-4 w-[90vw] sm:w-[380px] h-[70vh] sm:h-[600px] opacity-100 scale-100 rounded-[2rem]' 
            : 'bottom-6 right-6 w-0 h-0 opacity-0 scale-0 rounded-full'
          }
        `}
      >
        {/* Header */}
        <div className="p-4 bg-gradient-to-r from-primary/20 via-surface to-secondary/20 border-b border-white/10 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="relative">
              <div className="w-10 h-10 rounded-full bg-black/40 flex items-center justify-center border border-primary/50 shadow-inner text-primary">
                 <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-6 h-6">
                    <path strokeLinecap="round" strokeLinejoin="round" d="M9 17.25v1.007a3 3 0 01-.879 2.122L7.5 21h9l-.621-.621A3 3 0 0115 18.257V17.25m6-12V15a2.25 2.25 0 01-2.25 2.25H5.25A2.25 2.25 0 013 15V5.25m18 0A2.25 2.25 0 0018.75 3H5.25A2.25 2.25 0 003 5.25m18 0V12a2.25 2.25 0 01-2.25 2.25H5.25A2.25 2.25 0 013 12V5.25" />
                 </svg>
              </div>
              <div className="absolute bottom-0 right-0 w-2.5 h-2.5 bg-green-500 rounded-full border border-surface shadow-[0_0_10px_rgba(34,197,94,0.8)]"></div>
            </div>
            <div>
              <h3 className="font-orbitron font-bold text-white text-sm tracking-wider">NOVA NEXUS</h3>
              <p className="text-[10px] text-primary/80 font-bold uppercase tracking-widest animate-pulse">AI Online</p>
            </div>
          </div>
          <button onClick={() => setIsOpen(false)} className="w-8 h-8 rounded-full bg-white/5 flex items-center justify-center text-text-secondary hover:text-white hover:bg-white/10 transition-colors">
            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-5 h-5">
              <path strokeLinecap="round" strokeLinejoin="round" d="M19.5 8.25l-7.5 7.5-7.5-7.5" />
            </svg>
          </button>
        </div>

        {/* Messages Area */}
        <div className="flex-1 overflow-y-auto p-4 space-y-6 custom-scrollbar bg-gradient-to-b from-transparent to-black/20">
          {messages.map((msg) => (
            <div 
              key={msg.id} 
              className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2 duration-300`}
            >
              <div 
                className={`max-w-[85%] p-4 rounded-2xl text-xs md:text-sm leading-relaxed shadow-lg backdrop-blur-sm ${
                  msg.sender === 'user' 
                    ? 'bg-gradient-to-br from-primary to-primary/80 text-black font-bold rounded-tr-none' 
                    : msg.isError 
                      ? 'bg-red-500/10 text-red-200 border border-red-500/30 rounded-tl-none'
                      : 'bg-white/5 text-text-secondary border border-white/10 rounded-tl-none hover:border-primary/30 transition-colors'
                }`}
              >
                {msg.text}
                <div className={`text-[9px] mt-2 opacity-60 font-mono text-right ${msg.sender === 'user' ? 'text-black' : 'text-text-secondary'}`}>
                  {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </div>
              </div>
            </div>
          ))}

          {isTyping && (
            <div className="flex justify-start">
              <div className="bg-white/5 px-4 py-3 rounded-2xl rounded-tl-none border border-white/5 flex space-x-1 items-center">
                <div className="w-1.5 h-1.5 bg-primary rounded-full animate-bounce"></div>
                <div className="w-1.5 h-1.5 bg-primary rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
