                  rel="noopener noreferrer"
                  className="mt-2 bg-green-500 hover:bg-green-600 text-white text-xs font-bold py-2 px-4 rounded-xl flex items-center shadow-[0_0_15px_rgba(34,197,94,0.4)] transition-all hover:scale-105"
                >
                  <i className="fab fa-whatsapp mr-2 text-lg"></i> Chat on WhatsApp
                </a>
              )}
            </div>
          ))}

          {isTyping && (
            <div className="flex justify-start">
              <div className="bg-white/5 px-4 py-3 rounded-2xl rounded-tl-none border border-white/5 flex space-x-1 items-center">
                <div className="w-1.5 h-1.5 bg-primary rounded-full animate-bounce"></div>
